/************************************************************
** 函数名称 ：void Write_32bit(u32 dat)
** 函数功能 ：AD9910串行口写入数据
** 入口参数 ：32位寄存器数据
** 出口参数 ：无
** 函数说明 ：无
**************************************************************/
void Write_32bit(u32 dat)
{
    u8 i;
    u32 com;
    com = 0x80000000;
    AD9910_SCLK_0;

    for (i = 0; i < 32; i++)
    {
        if ((dat & com) == 0)
            AD9910_SDIO_0;
        else
            AD9910_SDIO_1;

        AD9910_SCLK_1;
        com = com >> 1;
        AD9910_SCLK_0;
    }
}

/************************************************************
** 函数名称 ：void txd_8bit(uchar txdat)
** 函数功能 ：AD9910串行口写入数据
** 入口参数 ：8位寄存器数据
** 出口参数 ：无
** 函数说明 ：无
**************************************************************/
void txd_8bit(uchar txdat)
{
    uchar i, sbt;
    sbt = 0x80;
    // while (HAL_GPIO_ReadPin(AD9910_SCLK_GPIO_Port, AD9910_SCLK_Pin) != GPIO_PIN_RESET)
    //     AD9910_SCLK_0;
    for (i = 0; i < 8; i++)
    {
        if ((txdat & sbt) == 0)
            AD9910_SDIO_0;
        else
            AD9910_SDIO_1;
        // while (HAL_GPIO_ReadPin(AD9910_SCLK_GPIO_Port, AD9910_SCLK_Pin) != GPIO_PIN_SET)
        AD9910_SCLK_1;

        sbt = sbt >> 1;
        // while (HAL_GPIO_ReadPin(AD9910_SCLK_GPIO_Port, AD9910_SCLK_Pin) != GPIO_PIN_RESET)
        AD9910_SCLK_0;
    }
}

/************************************************************
** 函数名称 ：void Init_ad9910(void))
** 函数功能 ：初始化AD9910的管脚和最简单的内部寄存器的配置，
** 入口参数 ：无
** 出口参数 ：无
** 函数说明 ：无
**************************************************************/
void Init_AD9910(void)
{
    uchar k, m;

    AD9910_PWR_0;
    AD9910_PROFILE0_0;
    AD9910_PROFILE1_0;
    AD9910_PROFILE2_0;
    AD9910_DRCTL_0;
    AD9910_DPH_0;
    AD9910_MAS_REST_1;
    delay_ms(5);
    AD9910_MAS_REST_0;

    AD9910_CS_0;
    txd_8bit(0x00);
    for (m = 0; m < 4; m++)
        txd_8bit(cfr1[m]);
    while (HAL_GPIO_ReadPin(AD9910_CS_GPIO_Port, AD9910_CS_Pin) != GPIO_PIN_SET)
        AD9910_CS_1;

    for (k = 0; k < 10; k++)
        ;

    AD9910_CS_0;
    txd_8bit(0x01);
    for (m = 0; m < 4; m++)
        txd_8bit(cfr2[m]);
    AD9910_CS_1;
    for (k = 0; k < 10; k++)
        ;

    AD9910_CS_0;
    while (HAL_GPIO_ReadPin(AD9910_CS_GPIO_Port, AD9910_CS_Pin) != GPIO_PIN_RESET)
        AD9910_CS_0;

    txd_8bit(0x02);
    for (m = 0; m < 4; m++)
        txd_8bit(cfr3[m]);
    AD9910_CS_1;
    while (HAL_GPIO_ReadPin(AD9910_CS_GPIO_Port, AD9910_CS_Pin) != GPIO_PIN_SET)
        AD9910_CS_1;

    for (k = 0; k < 10; k++)
        ;

    AD9910_UP_DAT_1;

    for (k = 0; k < 10; k++)
        ;
    AD9910_UP_DAT_0;

    delay_ms(1);
    HAL_UART_Transmit(&huart3, (uint8_t *)"AD9910 Init OK!\r\n", 17, 1000); // ��ʼ�������ʾ

    // AD9910_PWR_1;
    // delay_ms(10);
    // AD9910_PROFILE1_1;
    // AD9910_DRCTL_1; //
    // AD9910_DRHOLD_1;
}
/************************************************************
** 函数名称 ：void Txfrc(void))
** 函数功能 ：向AD9910芯片发送频率，幅度等相关控制数据
** 入口参数 ：无
** 出口参数 ：无
** 函数说明 ：无
**************************************************************/
void Txfrc(void)
{
    uchar m;

    AD9910_CS_0;
    txd_8bit(0x0e);
    for (m = 0; m < 8; m++)
        txd_8bit(profile11[m]);
    AD9910_CS_1;

    AD9910_UP_DAT_1;
    AD9910_UP_DAT_0;
}
/************************************************************
** 函数名称 ：void AD9910_FreWrite(void))
** 函数功能 ：将需要的频率转换为对应的控制数据，保存进profile11并发送到芯片
** 入口参数 ：目标频率，单位Hz，范围0~420000000
** 出口参数 ：无
** 函数说明 ：无
**************************************************************/
void AD9910_FreWrite(ulong Freq)
{
    ulong Temp;
    Temp = (ulong)Freq * 4.294967296; //将输入频率因子分为四个字节  主频1GHz，32位相位累加器，故每Hz在的控制字增量 delta =  4.294967296 = (2^32)/1000000000
    profile11[7] = (uchar)Temp;
    profile11[6] = (uchar)(Temp >> 8);
    profile11[5] = (uchar)(Temp >> 16);
    profile11[4] = (uchar)(Temp >> 24);
    Txfrc();
}

/************************************************************
** 函数名称 ：void AD9910_AmpWrite(void))
** 函数功能 ：将幅度控制数据保存到profile11并写入芯片
** 入口参数 ：幅度控制字，范围0~16383
** 出口参数 ：无
** 函数说明 ：14位幅度控制字，控制数据0~16383对应输出幅度0~800mV左右
**************************************************************/
void AD9910_AmpWrite(uint16_t Amp)
{
    profile11[0] = (Amp % 16384) >> 8;
    profile11[1] = (Amp % 16384) & 0xff;
    Txfrc();
}

/************************************************************
** 函数名称 ：AD9910_RAM_WAVE_Set(AD9910_WAVE_ENUM wave)
** 函数功能 ：设置AD9910,RAM功能，向AD9910芯片内部RAM写入1024个点的波形数据，使模块可输出任意波形
                            目前仅定义了三角波，方波，SINC波，三种波形数组
                            用户也可自定义数组数据，使波形输出自己定义的任意波形(1024个数据，每个数据范围：0~16383)
** 入口参数 ：wave： TRIG_WAVE：三角波，SQUARE_WAVE：方波，SINC_WAVE：SINC波
** 出口参数 ：无
** 函数说明 ：RAM播放速率决定了输出波形的频率，输出频率与播放速率控制字参考以下说明
**************************************************************/
void AD9910_RAM_WAVE_Set(AD9910_WAVE_ENUM wave)
{
    int i;
    const uint32_t *srcWaveDta;

    /* CFR1 控制寄存器配置:
     * 0x40, 0x40, 0x00, 0x00 -> 开启 RAM 使能位(Bit 31) 和 RAM 目的地址位 */
    uint8_t CFR1[] = {0x40, 0x40, 0x00, 0x00};

    /* RAM Profile0 寄存器配置 (地址 0x0E):
     * 配置起始地址、结束地址、步进速率和模式
     * 这里的计算公式: 频率 = Fsysclk / (4 * StepRate) / 样本点数
     * 例如: 1GHz / (4 * 1) / 1024 = 244.14 kHz
     */
    uint8_t RAM_Profile0[] = {
        0x00, 0x00, // Address Step Rate (1)
        0x01, 0xFF, // End Address (1023)
        0xC0,       // Start Address (0)
        0x00, 0x00,
        0x04        // Mode Control: 0x04 = Continuous Ramp Up
    };

    // 1. 写入 CFR1 寄存器 (地址 0x00)
    AD9910_CS_0;
    txd_8bit(0x00);
    for (i = 0; i < 4; i++) {
        txd_8bit(CFR1[i]);
    }
    AD9910_CS_1;

    // 2. 写入 Profile 0 寄存器 (地址 0x0E)
    AD9910_CS_0;
    txd_8bit(0x0E);
    for (i = 0; i < 8; i++) {
        txd_8bit(RAM_Profile0[i]);
    }
    AD9910_CS_1;

    // 3. 发送更新信号，使寄存器配置生效
    AD9910_UP_DAT_0;
    AD9910_UP_DAT_1;
    AD9910_UP_DAT_0;

    // 4. 选择波形数据源
    switch (wave)
    {
    case TRIG_WAVE:   srcWaveDta = RAM_TRIG_WAVE;   break;
    case SQUARE_WAVE: srcWaveDta = RAM_SQUARE_WAVE; break;
    case SINC_WAVE:   srcWaveDta = RAM_SINC_WAVE;   break;
    default:          srcWaveDta = RAM_TRIG_WAVE;   break;
    }

    // 5. 写入 RAM 数据 (地址 0x16)
    AD9910_CS_0;
    txd_8bit(0x16);
    for (i = 0; i < 1024; i++)
    {
        /* AD9910 RAM 为 32位，数据高 14 位有效 (取决于目标地址)
         * 这里左移 18 位是为了将 14 位幅值数据对齐到高位 */
        Write_32bit(srcWaveDta[i] << 18);
    }
    AD9910_CS_1;

    // 6. 最终使能 RAM 运行模式
    AD9910_CS_0;
    txd_8bit(0x00);
    CFR1[0] |= 0x80; // 将 CFR1[31] 置 1，正式开启 RAM
    for (i = 0; i < 4; i++) {
        txd_8bit(CFR1[i]);
    }
    AD9910_CS_1;

    // 7. 再次更新，波形开始输出
    AD9910_UP_DAT_0;
    AD9910_UP_DAT_1;
    AD9910_UP_DAT_0;
}
/************************************************************
** 函数名称 ：void AD9910_DRG_FreInit_AutoSet(FunctionalState autoSweepEn)
** 函数功能 ：开启AD9910的数字斜坡模式DRG模式使能，使能数字斜坡控制频率，根据参数设置是否自动扫频
** 入口参数 ：autoSweepEn：ENABLE,使能自动扫频，
                        此时无需外部控制,芯片自动从下限频率扫描到上限频率，再自动从上限频率扫描到下限频率，以此自动循环，实现上下双方向自动循环扫频

                        autoSweepEn：DISABLE,关闭自动扫频，
                        此时需外部引脚DRCTL脚控制扫频，不能自动扫频，扫频方向取决于DRCTL逻辑电平
                        DRCTL引脚置高(3.3V)，AD9910从下限频率扫描到上限频率，扫描完成后保持在上限频率
                        DRCTL引脚置低(  0V)，AD9910从上限频率扫描到下限频率，扫描完成后保持在下限频率

** 出口参数 ：无
** 函数说明 ：	autoSweepEn设置为ENABLE时，自动扫频，扫描完成自动换向，扫频速率可极高；
                            autoSweepEn设置为DISABLE时，可由DRCTL脚程控或者外接线控，实现手动控制扫频
**************************************************************/
void AD9910_DRG_FreInit_AutoSet(FunctionalState autoSweepEn)
{
    /* CFR1 寄存器配置 (地址 0x00):
     * 0x00, 0x40, 0x00, 0x00 -> 开启 Inverse Sinc 滤波器 (Bit 22)
     * 注意：如果需要 RAM 和 DRG 同时协作，配置会有所不同 */
    uint8_t CFR1[] = {0x00, 0x40, 0x00, 0x00};

    /* CFR2 寄存器配置 (地址 0x01):
     * 默认配置: 0x00, 0x48, 0x08, 0x20
     * Bit 19: Enable DRG (Digital Ramp Enable)
     * Bit 3:  Internal I/O Update Active (如果需要内部自动更新)
     */
    uint8_t CFR2[] = {0x00, 0x48, 0x08, 0x20};
    int j;

    /* 如果开启自动扫描模式:
     * CFR2[1] |= 0x06 对应的是寄存器低位字节的 Bit 1 和 Bit 2
     * Bit 1 (0x02): Digital Ramp No-Dwell High
     * Bit 2 (0x04): Digital Ramp No-Dwell Low
     * 这通常用于让频率在达到峰值后立即返回，而不是停留在端点 */
    if (autoSweepEn == ENABLE)
    {
        CFR2[3] |= 0x08; // 确保 Digital Ramp Enable (Bit 19 在第三个字节) 被置位
        CFR2[1] |= 0x06; // 设置 No-Dwell 模式
    }

    // 1. 写入 CFR1 寄存器 (地址 0x00)
    AD9910_CS_0;
    txd_8bit(0x00);
    for (j = 0; j < 4; j++)
    {
        txd_8bit(CFR1[j]);
    }
    AD9910_CS_1;

    // 2. 写入 CFR2 寄存器 (地址 0x01)
    AD9910_CS_0;
    txd_8bit(0x01);
    for (j = 0; j < 4; j++)
    {
        txd_8bit(CFR2[j]);
    }
    AD9910_CS_1;

    // 3. 产生 IO_UPDATE 脉冲，使配置生效
    AD9910_UP_DAT_0;
    AD9910_UP_DAT_1;
    AD9910_UP_DAT_0;
}


/**
 * @brief 设置 AD9910 DRG 扫描参数 (频率扫描)
 * @param lowFre: 扫描下限频率 (Hz)
 * @param upFre:  扫描上限频率 (Hz)
 * @param posStep: 正向步进频率 (Hz) - 递增时的频率跳变大小
 * @param negStep: 负向步进频率 (Hz) - 递减时的频率跳变大小
 * @param posRate: 正向步进速率 (16-bit) - 递增的时间间隔计数
 * @param negRate: 负向步进速率 (16-bit) - 递减的时间间隔计数
 */
void AD9910_DRG_FrePara_Set(uint32_t lowFre, uint32_t upFre, uint32_t posStep, uint32_t negStep, uint16_t posRate, uint16_t negRate)
{
    uint32_t upper, lower, dec, inc;
    int i;

    // 寄存器数组初始化
    uint8_t DRL[] = {0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00}; // 0x0B: Digital Ramp Limit (上限与下限)
    uint8_t DRS[] = {0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00}; // 0x0C: Digital Ramp Step Size (步进值)
    uint8_t DRR[] = {0x00, 0x00, 0x00, 0x00};                         // 0x0D: Digital Ramp Rate (速率/定时)

    /* 频率换算公式: FTW = (Frequency * 2^32) / Fsysclk
     * 假设系统时钟 Fsysclk = 1GHz, 则系数为 4.294967296
     */
    const double factor = 4.294967296;

    upper = (uint32_t)(upFre * factor);
    lower = (uint32_t)(lowFre * factor);
    dec   = (uint32_t)(negStep * factor);
    inc   = (uint32_t)(posStep * factor);

    // 1. 配置 Digital Ramp Limit (0x0B): [63:32] 上限, [31:0] 下限
    DRL[0] = (uint8_t)(upper >> 24);
    DRL[1] = (uint8_t)(upper >> 16);
    DRL[2] = (uint8_t)(upper >> 8);
    DRL[3] = (uint8_t)upper;
    DRL[4] = (uint8_t)(lower >> 24);
    DRL[5] = (uint8_t)(lower >> 16);
    DRL[6] = (uint8_t)(lower >> 8);
    DRL[7] = (uint8_t)lower;

    // 2. 配置 Digital Ramp Step Size (0x0C): [63:32] 减少步进, [31:0] 增加步进
    DRS[0] = (uint8_t)(dec >> 24);
    DRS[1] = (uint8_t)(dec >> 16);
    DRS[2] = (uint8_t)(dec >> 8);
    DRS[3] = (uint8_t)dec;
    DRS[4] = (uint8_t)(inc >> 24);
    DRS[5] = (uint8_t)(inc >> 16);
    DRS[6] = (uint8_t)(inc >> 8);
    DRS[7] = (uint8_t)inc;

    // 3. 配置 Digital Ramp Rate (0x0D): [31:16] 负向速率, [15:0] 正向速率
    // 时间间隔 dt = Rate * (4 / Fsysclk)
    DRR[0] = (uint8_t)(negRate >> 8);
    DRR[1] = (uint8_t)negRate;
    DRR[2] = (uint8_t)(posRate >> 8);
    DRR[3] = (uint8_t)posRate;

    // SPI 写入过程
    AD9910_CS_0;
    txd_8bit(0x0B);
    for (i = 0; i < 8; i++) txd_8bit(DRL[i]);
    AD9910_CS_1;

    AD9910_CS_0;
    txd_8bit(0x0C);
    for (i = 0; i < 8; i++) txd_8bit(DRS[i]);
    AD9910_CS_1;

    AD9910_CS_0;
    txd_8bit(0x0D);
    for (i = 0; i < 4; i++) txd_8bit(DRR[i]);
    AD9910_CS_1;

    // 产生更新信号
    AD9910_UP_DAT_0;
    AD9910_UP_DAT_1;
    AD9910_UP_DAT_0;
}